oxy_webhelp_navlinks = {"archiving_dc_workloads_azure-d27243e6133":{"topics":[{"title":"Archive preparation in Azure","shortdesc":"<p class=\"shortdesc\">Preparing Azure storage for archiving involves creating a storage account and         following a Service Principal model in Azure.<\/p>","href":"archival\/archive_preparation_in_azure.html","attributes":{"data-id":"archive_preparation_in_azure"},"menu":{"hasChildren":false},"tocID":"archive_preparation_in_azure-d27243e6147","next":"archive_preparation_in_azure-d27243e6147"},{"title":"Creating an Azure cloud account with OAuth for data center archival locations","shortdesc":"<p class=\"shortdesc\">Create an Azure cloud account in <span class=\"ph\">RSC<\/span> using OAuth configuration to         provide <span class=\"ph\">RSC<\/span> with Service Principal-based access and permissions to manage a         data center archival location in an Azure storage account.<\/p>","href":"archival\/creating_azr_cloud_accnt_with_oauth_dc_arch_loc.html","attributes":{"data-id":"creating_azr_cloud_accnt_with_oauth_dc_arch_loc"},"menu":{"hasChildren":false},"tocID":"creating_azr_cloud_accnt_with_oauth_dc_arch_loc-d27243e6191","topics":[]},{"title":"Creating an Azure cloud account without OAuth for data center archival locations","shortdesc":"<p class=\"shortdesc\">Create an Azure cloud account in <span class=\"ph\">RSC<\/span> without an OAuth configuration         to provide Rubrik with Service Principal-based access and permissions to manage a data         center archival location in an Azure storage account.<\/p>","href":"archival\/creating_azr_cloud_accnt_without_oauth_dc_arch_loc.html","attributes":{"data-id":"creating_azr_cloud_accnt_without_oauth_dc_arch_loc"},"menu":{"hasChildren":false},"tocID":"creating_azr_cloud_accnt_without_oauth_dc_arch_loc-d27243e6208","next":"creating_azr_cloud_accnt_without_oauth_dc_arch_loc-d27243e6208"},{"title":"Creating an access key based Azure cloud account for data center archival locations","shortdesc":"<p class=\"shortdesc\">Create an Azure cloud account in <span class=\"ph\">RSC<\/span> to provide <span class=\"ph\">RSC<\/span>         with access key based access and permissions to manage a data center archival location in an         Azure storage account.<\/p>","href":"archival\/creating_azr_acc_ak_dc_arch_loc.html","attributes":{"data-id":"creating_azr_acc_ak_dc_arch_loc"},"menu":{"hasChildren":false},"tocID":"creating_azr_acc_ak_dc_arch_loc-d27243e6236","topics":[]},{"title":"Editing a service principal based Azure cloud account","shortdesc":"<p class=\"shortdesc\">You can edit an Azure cloud account without OAuth, configured with the service         principal based authentication method to update the client secret key for snapshot archival         operations.<\/p>","href":"archival\/editing_service_principal_based_azr_cloud_account.html","attributes":{"data-id":"editing_service_principal_based_azr_cloud_account"},"menu":{"hasChildren":false},"tocID":"editing_service_principal_based_azr_cloud_account-d27243e6253","topics":[]},{"title":"Deleting a service principal based Azure cloud account","shortdesc":"<p class=\"shortdesc\">You can delete an Azure cloud account configured with the Service Principal based         authentication method for snapshot archival operations if you do not want <span class=\"ph\">RSC<\/span> to access the Azure subscription specified in the cloud         account.<\/p>","href":"archival\/deleting_service_principal_based_azr_cloud_account.html","attributes":{"data-id":"deleting_service_principal_based_azr_cloud_account"},"menu":{"hasChildren":false},"tocID":"deleting_service_principal_based_azr_cloud_account-d27243e6264","topics":[]},{"title":"Azure archival locations with immutable storage","shortdesc":"<p class=\"shortdesc\">Azure archival locations with immutable storage protect data from being modified or         deleted from archives. Rubrik supports immutable storage on Azure archival locations at the         blob level and at the container level.<\/p>","href":"archival\/azr_immutable_archival_locations.html","attributes":{"data-id":"azr_immutable_archival_locations"},"menu":{"hasChildren":false},"tocID":"azr_immutable_archival_locations-d27243e6278","next":"azr_immutable_archival_locations-d27243e6278"},{"title":"Azure Archive tiering options","shortdesc":"<p class=\"shortdesc\">You can configure archive tiering for Azure archival locations to place older data to         the Archive tier based on an SLA Domain policy.<\/p>","href":"archival\/azure_archive_tiering.html","attributes":{"data-id":"azure_archive_tiering"},"menu":{"hasChildren":false},"tocID":"azure_archive_tiering-d27243e6347","next":"azure_archive_tiering-d27243e6347"},{"title":"Azure archival location settings","shortdesc":"<p class=\"shortdesc\">Information about the settings required for creating an Azure archival location for a         Rubrik cluster.<\/p>","href":"archival\/azure_archival_location_settings.html","attributes":{"data-id":"azure_archival_location_settings"},"menu":{"hasChildren":false},"tocID":"azure_archival_location_settings-d27243e6386","topics":[]},{"title":"Azure cloud compute settings","shortdesc":"<p class=\"shortdesc\">Information about the cloud compute settings required for Archival Consolidation         during Azure archival location configuration.<\/p>","href":"archival\/arch_azure_cloud_compute_settings.html","attributes":{"data-id":"arch_azure_cloud_compute_settings"},"menu":{"hasChildren":false},"tocID":"arch_azure_cloud_compute_settings-d27243e6397","topics":[]},{"title":"Switching access types in Azure archival location settings","shortdesc":"<p class=\"shortdesc\">You can switch the access type to either Service Principal Based or Access Key Based,         by editing the Azure archival location settings. The specified access type authenticates the             <span class=\"ph\">Rubrik Security Cloud<\/span> account for accessing the Azure storage account when creating         an archival location.<\/p>","href":"archival\/switching_access_types_azr_arch_loc_settings.html","attributes":{"data-id":"switching_access_types_azr_arch_loc_settings"},"menu":{"hasChildren":false},"tocID":"switching_access_types_azr_arch_loc_settings-d27243e6409","topics":[]},{"title":"Azure Cold tier support for archival location","shortdesc":"<p class=\"shortdesc\">When you want to store data for a longer duration and access the data infrequently,         you can transfer the data to an archival location from the default Hot or Cool access tier         to the Cold access tier by using the Azure storage lifecycle management policy.<\/p>","href":"archival\/azure_cold_tier_support_archival_location.html","attributes":{"data-id":"azure_cold_tier_support_archival_location"},"menu":{"hasChildren":false},"tocID":"azure_cold_tier_support_archival_location-d27243e6423","next":"azure_cold_tier_support_archival_location-d27243e6423"}]}};